            for j, val in enumerate(row):
                if val == 1:
                    pygame.draw.rect(self.screen, (255, 0, 0), (self.x + j * 30, self.y + i * 30, 30, 30))

    def draw_score(self):
        for i, score in enumerate(self.scores):
            text = self.font.render(f'Player {i+1}: {score}', True, (255, 255, 255))
            self.screen.blit(text, (10, 10 + i * 40))

    def draw_contributions(self):
        for i, contribution in enumerate(self.contributions):
            text = self.font.render(f'Player {i+1} contribution: {contribution}%', True, (255, 255, 255))
            self.screen.blit(text, (10, 150 + i * 40))

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                quit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.x -= 30
                elif event.key == pygame.K_RIGHT:
                    self.x += 30
                elif event.key == pygame.K_DOWN:
                    self.y += 30
                elif event.key == pygame.K_SPACE:
                    self.scores[self.player_turn] += 1
                    self.contributions[self.player_turn] += 1 / self.players * 100
                    self.player_turn = (self.player_turn + 1) % self.players
                    self.tetromino = random.choice(self.tetrominoes)
                    self.x = self.screen_width // 2
                    self.y = 0

    def update(self):
        self.screen.fill((0, 0, 0))
        self.draw_tetromino()
        self.draw_score()
        self.draw_contributions()
        self.handle_input()
        pygame.display.update()
        self.clock.tick(60)

    def run(self):
        while True:
            self.update()

