        self.screen_width = self.width * self.block_size
        self.screen_height = self.height * self.block_size
        self.players = [Player(i) for i in range(3)]
        self.current_player = 0
        self.score = 0
        self.grid = [[0 for _ in range(self.width)] for _ in range(self.height)]
        self.piece = self.get_new_piece()
        self.game_over = False

    def get_new_piece(self):
        return Piece(random.randint(0, 6))

    def update(self):
        if not self.game_over:
            self.piece.update(self)
            if self.piece.landed:
                self.add_piece_to_grid()
                self.clear_rows()
                self.piece = self.get_new_piece()
                self.current_player = (self.current_player + 1) % 3
            self.check_game_over()

    def add_piece_to_grid(self):
        for x, y in self.piece.get_coords():
            self.grid[y][x] = 1

    def clear_rows(self):
        rows_cleared = 0
        for row in self.grid:
            if all(cell == 1 for cell in row):
                self.grid.remove(row)
                self.grid.insert(0, [0 for _ in range(self.width)])
                rows_cleared += 1
        self.score += rows_cleared ** 2
        self.players[self.current_player].score += rows_cleared ** 2

    def check_game_over(self):
        if any(self.grid[0][i] == 1 for i in range(self.width)):
            self.game_over = True

    def render(self, screen):
        screen.fill((0, 0, 0))
        for y, row in enumerate(self.grid):
            for x, cell in enumerate(row):
                if cell == 1:
                    pygame.draw.rect(screen, (255, 255, 255), (x * self.block_size, y * self.block_size, self.block_size, self.block_size))
        self.piece.render(screen, self.block_size)
        font = pygame.font.Font(None, 36)
        text = font.render(f"Score: {self.score}", True, (255, 255, 255))
        screen.blit(text, (10, 10))
        for i, player in enumerate(self.players):
            text = font.render(f"Player {i+1} Score: {player.score}", True, (255, 255, 255))
            screen.blit(text, (10, 50 + i * 40))

class Piece:
    def __init__(self, type):
        self.type = type
        self.x = 5
        self.y = 0
        self.landed = False
        self.rotation = 0

    def update(self, game):
        if not self.landed:
            self.y += 1
            if self.y + self.get_height() > game.height:
                self.landed = True
                self.y = game.height - self.get_height()
            for x, y in self.get_coords():
                if x < 0 or x >= game.width or y < 0 or y >= game.height or game.grid[y][x] == 1:
                    self.landed = True
                    self.y -= 1
                    break

    def get_coords(self):
        if self.type == 0:
            return [(self.x, self.y), (self.x + 1, self.y), (self.x + 2, self.y), (self.x + 3, self.y)]
        elif self.type == 1:
            return [(self.x, self.y), (self.x + 1, self.y), (self.x, self.y + 1), (self.x + 1, self.y + 1)]
        elif self.type == 2:
            return [(self.x, self.y), (self.x + 1, self.y), (self.x + 2, self.y), (self.x + 2, self.y + 1)]
        elif self.type == 3:
            return [(self.x, self.y), (self.x + 1, self.y), (self.x + 2, self.y), (self.x, self.y + 1)]
        elif self.type == 4:
            return [(self.x, self.y), (self.x + 1, self.y), (self.x, self.y + 1), (self.x - 1, self.y + 1)]
        elif self.type == 5:
            return [(self.x, self.y), (self.x + 1, self.y), (self.x + 1, self.y + 1), (self.x + 2, self.y + 1)]
        elif self.type == 6:
            return [(self.x, self.y), (self.x + 1, self.y), (self.x + 1, self.y + 1), (self.x, self.y + 1)]

    def get_height(self):
        if self.type == 0:
            return 1
        elif self.type == 1:
            return 2
        elif self.type == 2:
            return 2
        elif self.type == 3:
            return 2
        elif self.type == 4:
            return 2
        elif self.type == 5:
            return 2
        elif self.type == 6:
            return 2

    def render(self, screen, block_size):
        for x, y in self.get_coords():
            pygame.draw.rect(screen, (255, 255, 255), (x * block_size, y * block_size, block_size, block_size))

