        self.screen_width = self.width * self.block_size
        self.screen_height = self.height * self.block_size
        self.players = [Player(1), Player(2), Player(3)]
        self.current_player = 0
        self.score = 0
        self.contributions = [0, 0, 0]
        self.screen = pygame.display.set_mode((self.screen_width, self.screen_height))
        self.font = pygame.font.Font(None, 36)
        self.clock = pygame.time.Clock()
        self.running = True
        self.tetrominoes = []
        self.new_tetromino()

    def new_tetromino(self):
        self.tetrominoes.append(Tetromino(random.randint(0, 6)))

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.tetrominoes[-1].x -= 1
                elif event.key == pygame.K_RIGHT:
                    self.tetrominoes[-1].x += 1
                elif event.key == pygame.K_DOWN:
                    self.tetrominoes[-1].y += 1
                elif event.key == pygame.K_UP:
                    self.tetrominoes[-1].rotate()
                elif event.key == pygame.K_SPACE:
                    self.drop_tetromino()

    def drop_tetromino(self):
        while self.tetrominoes[-1].y < self.height - self.tetrominoes[-1].height:
            self.tetrominoes[-1].y += 1
        self.lock_tetromino()
        self.new_tetromino()

    def lock_tetromino(self):
        for block in self.tetrominoes[-1].blocks:
            if block[1] >= self.height:
                self.running = False
            else:
                self.score += 1
                self.contributions[self.current_player] += 1
                self.current_player = (self.current_player + 1) % 3

    def render(self):
        self.screen.fill((0, 0, 0))
        for tetromino in self.tetrominoes:
            for block in tetromino.blocks:
                pygame.draw.rect(self.screen, (255, 255, 255), (block[0] * self.block_size, block[1] * self.block_size, self.block_size, self.block_size))
