        self.screen.blit(player_text, (10, 50))
        contribution_text = self.font.render(f'Contributions: {self.contributions[0]} {self.contributions[1]} {self.contributions[2]}', True, (255, 255, 255))
        self.screen.blit(contribution_text, (10, 90))
        pygame.display.flip()

    def run(self):
        while self.running:
            self.handle_events()
            self.render()
            self.clock.tick(60)

