        self.score = 0
        self.piece = None
        self.x = 0
        self.y = 0

    def move_down(self, game):
        if self.y + len(self.piece) < game.height and not game.check_collision(self.piece, self.x, self.y + 1):
            self.y += 1
        else:
            game.grid[self.y:self.y + len(self.piece)] = [row[:self.x] + [val for val in row[self.x:self.x + len(self.piece[0])]] + row[self.x + len(self.piece[0]):] for row, piece_row in zip(game.grid[self.y:self.y + len(self.piece)], self.piece)]
            for i, row in enumerate(game.grid):
                if all(row):
                    game.remove_row(i)
                    game.update_score(1)
            game.switch_player()

    def move_side(self, game, dx):
        if self.x + dx >= 0 and self.x + dx + len(self.piece[0]) <= game.width and not game.check_collision(self.piece, self.x + dx, self.y):
            self.x += dx

    def rotate(self, game):
        self.piece = game.rotate(self.piece)
        if game.check_collision(self.piece, self.x, self.y):
            self.piece = game.rotate(game.rotate(game.rotate(self.piece)))

