                            y += 1
                        self.tetris.update_grid(piece, x, y)
                    elif event.key == pygame.K_UP:
                        piece = self.tetris.get_new_piece()
                        x = self.tetris.width // 2
                        y = 0
                        while not self.tetris.check_collision(piece, x, y):
                            y += 1
                        y -= 1
                        piece = self.tetris.rotate(piece)
                        if not self.tetris.check_collision(piece, x, y):
                            self.tetris.update_grid(piece, x, y)
            self.screen.fill((0, 0, 0))
            self.draw_grid()
            self.draw_score()
            pygame.display.flip()
            self.tetris.update()
            self.clock.tick(60)
        pygame.quit()

