class Player:
    def __init__(self, name):
        self.name = name
        self.score = 0

class TetrisGame:
    def __init__(self, players):
        self.players = players
        self.current_player = 0
        self.scoreboard = {player.name: 0 for player in players}
        self.game_over = False
        self.board = [[0]*10 for _ in range(20)]
        self.piece = None
        self.next_piece = self.generate_piece()

    def generate_piece(self):
        import random
        pieces = ['I', 'J', 'L', 'O', 'S', 'T', 'Z']
        return random.choice(pieces)

    def rotate_piece(self):
        if self.piece == 'I':
            return 'I'
        elif self.piece == 'J':
            return 'L'
        elif self.piece == 'L':
            return 'J'
        elif self.piece == 'O':
            return 'O'
        elif self.piece == 'S':
            return 'Z'
        elif self.piece == 'T':
            return 'T'
        elif self.piece == 'Z':
            return 'S'

    def move_piece(self, direction):
        if direction == 'left':
            for i in range(len(self.board)):
                for j in range(len(self.board[i])):
                    if self.board[i][j] == 1:
                        if j > 0:
                            self.board[i][j-1] = 1
                            self.board[i][j] = 0
        elif direction == 'right':
            for i in range(len(self.board)):
                for j in range(len(self.board[i])):
                    if self.board[i][j] == 1:
                        if j < len(self.board[i]) - 1:
                            self.board[i][j+1] = 1
                            self.board[i][j] = 0
        elif direction == 'down':
            for i in range(len(self.board)-1, -1, -1):
                for j in range(len(self.board[i])):
                    if self.board[i][j] == 1:
                        if i < len(self.board) - 1:
                            self.board[i+1][j] = 1
                            self.board[i][j] = 0

    def drop_piece(self):
        self.piece = self.next_piece
        self.next_piece = self.generate_piece()
        self.board[0][5] = 1

    def check_collision(self):
        for i in range(len(self.board)):
            for j in range(len(self.board[i])):
                if self.board[i][j] == 1:
                    if i == len(self.board) - 1 or self.board[i+1][j] == 1:
                        return True
        return False

    def update_score(self):
        lines_cleared = 0
        for i in range(len(self.board)):
            if all(x == 1 for x in self.board[i]):
                lines_cleared += 1
                self.board.pop(i)
                self.board.insert(0, [0]*10)
        self.scoreboard[self.players[self.current_player].name] += lines_cleared * 100
        self.current_player = (self.current_player + 1) % len(self.players)

    def render(self):
        import os
        os.system('cls' if os.name == 'nt' else 'clear')
        print('Scoreboard:')
        for player in self.players:
            print(f'{player.name}: {self.scoreboard[player.name]}')
        print('\nGame Board:')
        for row in self.board:
            print(' '.join(['#' if x == 1 else '.' for x in row]))
        print(f'\nCurrent Player: {self.players[self.current_player].name}')
        print(f'Next Piece: {self.next_piece}')

    def play(self):
        while not self.game_over:
            self.render()
            action = input('Enter action (move left, move right, move down, rotate, drop): ')
            if action == 'move left':
                self.move_piece('left')
            elif action == 'move right':
                self.move_piece('right')
            elif action == 'move down':
                self.move_piece('down')
            elif action == 'rotate':
                self.piece = self.rotate_piece()
            elif action == 'drop':
                self.drop_piece()
            if self.check_collision():
                self.update_score()
            if all(x > 0 for x in self.scoreboard.values()) and sum(self.scoreboard.values()) > 1000:
                self.game_over = True
        self.render()
        print('Game Over!')

