        self.clock = pygame.time.Clock()
        self.running = True
        self.spawn_piece()
        while self.running:
            self.handle_events()
            self.update()
            self.render()
            self.clock.tick(60)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.move_piece(-1, 0)
                elif event.key == pygame.K_RIGHT:
                    self.move_piece(1, 0)
                elif event.key == pygame.K_DOWN:
                    self.move_piece(0, 1)
                elif event.key == pygame.K_UP:
                    self.rotate_piece()
                elif event.key == pygame.K_SPACE:
                    self.drop_piece()

    def update(self):
        if self.piece.y + len(self.piece.shape) >= self.height:
            self.lock_piece()
            self.spawn_piece()
        else:
            self.move_piece(0, 1)

    def render(self):
        self.screen.fill((0, 0, 0))
        for y, row in enumerate(self.grid):
            for x, cell in enumerate(row):
                if cell == 1:
                    pygame.draw.rect(self.screen, (255, 255, 255), (x*30, y*30, 30, 30))
        for y, row in enumerate(self.piece.shape):
            for x, cell in enumerate(row):
                if cell == 1:
                    pygame.draw.rect(self.screen, (255, 0, 0), ((self.piece.x + x)*30, (self.piece.y + y)*30, 30, 30))
        font = pygame.font.Font(None, 36)
