        self.screen.blit(text, (10, 10))
        text = font.render(f"Player {self.current_player+1}'s turn", True, (255, 255, 255))
        self.screen.blit(text, (10, 50))
        pygame.display.flip()

    def spawn_piece(self):
        self.piece = Piece(random.randint(0, self.width-1), 0)

    def move_piece(self, dx, dy):
        if self.is_valid_position(self.piece.x + dx, self.piece.y + dy):
            self.piece.x += dx
            self.piece.y += dy

    def rotate_piece(self):
        self.piece.shape = [list(reversed(x)) for x in zip(*self.piece.shape)]
        if not self.is_valid_position(self.piece.x, self.piece.y):
            self.piece.shape = [list(x) for x in zip(*reversed(self.piece.shape))]

    def drop_piece(self):
        while self.is_valid_position(self.piece.x, self.piece.y + 1):
            self.piece.y += 1

    def lock_piece(self):
        for y, row in enumerate(self.piece.shape):
            for x, cell in enumerate(row):
                if cell == 1:
                    self.grid[self.piece.y + y][self.piece.x + x] = 1
