    def __init__(self):
        self.contributors = []

    def add_contributor(self, name, contribution):
        self.contributors.append((name, contribution))

    def calculate_scores(self):
        total_contributions = sum(contribution for _, contribution in self.contributors)
        scores = []
        for name, contribution in self.contributors:
            score = contribution / total_contributions
            scores.append((name, score))
        return scores

    def distribute(self, amount):
        scores = self.calculate_scores()
        distribution = []
        for name, score in scores:
            share = amount * score
            distribution.append((name, share))
